            print(f"Set cpc_symbols with {len(cpc_symbols)} records")
        break

print("=== SUMMARY ===")
print(f"Publication data loaded: {pub_data is not None}")
print(f"CPC symbols loaded: {cpc_symbols is not None}")

if pub_data:
